210:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
211:     // longer than 16.
212:     buffer_effective: [16]Span,
213:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
214:     // value (255), we will reset the effective buffer and this value.
215:     buffer_length: u8 = 0,
216:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
217:     // calculate backspaces and replacement characters.
218:     buffer_modification_index: ?u8 = null,
219:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
220:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
221:     // and the engine is working on position on or after literal index, the engine will skip
222:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
223:     literal_index: ?u8 = null,
224:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
225:     mode: InputMode = .literal,
226: 
227:     // Initialize the State on allocated memory.
228:     fn init(self: *State) void {
229:         self.* = .{
230:             .buffer_effective = undefined,
231:         };
232:     }
233: 
234:     fn add(self: *State, c: u8) void {
235:         // Only allow a-zA-Z.
236:         assert(std.ascii.isAlphabetic(c));
237: 
238:         // The buffer_modification index must be inbound of the buffer_effective.
239:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
240: 
241:         // Input mode must be either .literal or .telex.
242:         assert(self.mode == .literal or self.mode == .telex);
243: 
244:         // Should never set literal_index in .literal mode.
245:         if (self.mode == .literal) {
246:             assert(self.literal_index == null);
247:         }
248: 
249:         if (self.literal_index) |literal_index| {
250:             // When literal_index is set, mode must be .telex.
251:             assert(self.mode == .telex);
252:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
253:             // because we won't process Vietnamese input outside the buffer_effective.
254:             assert(literal_index <= self.buffer_effective.len);
255:             // The literal_index value must be less than buffer length.
256:             assert(literal_index < self.buffer_length);
257:         }
258: 
259:         switch (c) {
