540:     // Append literal character when possible. Then inclease the buffer_length.
541:     fn append_literal(self: *State, c: u8) void {
542:         // Only allow a-zA-Z.
543:         assert(std.ascii.isAlphabetic(c));
544: 
545:         // Check if we can add new span for input character.
546:         if (self.buffer_length < self.buffer_effective.len) {
547:             // Add character to span.
548:             self.buffer_effective[self.buffer_length] = Span.init(c);
549:         }
550:         // Increase the buffer length for tracking, we will need it went handling backspace.
551:         self.buffer_length = self.buffer_length + 1;
552:     }
553: 
554:     // Return the last item in buffer_effective, not valid if the buffer_length is out of range.
555:     fn buffer_effective_last(self: *State) Span {
556:         // Should not work if buffer_length exceed buffer_effective.
557:         assert(self.buffer_length <= self.buffer_effective.len);
558: 
559:         return self.buffer_effective[self.buffer_length - 1];
560:     }
561: 
562:     fn backspace(self: *State) void {
563:         // buffer_length must be positive for backspace.
564:         assert(self.buffer_length > 0);
565: 
566:         // Input mode must be either .literal or .telex.
567:         assert(self.mode == .literal or self.mode == .telex);
568: 
569:         if (self.literal_index) |literal_index| {
570:             // Input mode must be .telex when literal_index is set.
571:             assert(self.mode == .telex);
572:             // literal_index must be within buffer range when set.
573:             assert(literal_index < self.buffer_length);
574:         }
575: 
576:         // decrease the buffer_length to match the backspace.
577:         self.buffer_length -= 1;
578:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
579:         self.buffer_modification_index = null;
580:         // if the literal_index is out of buffer range, unset it.
581:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
582:             self.literal_index = null;
583:         }
584:     }
